// Package control provides immutable control plane enforcement.
// Lives outside repo at ~/.orch/ - agents cannot modify it.
package control

import (
	"bufio"
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"
)

var (
	// ControlDir is the immutable control plane directory
	ControlDir = filepath.Join(os.Getenv("HOME"), ".orch")

	// ConfigPath is the control plane config file
	ConfigPath = filepath.Join(ControlDir, "control-plane.conf")

	// HaltPath is the halt sentinel file
	HaltPath = filepath.Join(ControlDir, "halt")

	// MetricsDir is where metrics logs are stored
	MetricsDir = filepath.Join(ControlDir, "metrics")
)

// Config represents control plane configuration
type Config struct {
	MaxCommitsPerDay      int
	FixFeatRatioThreshold int
	ChurnRatioThreshold   int
	ProtectedPaths        []string
	CooldownMinutes       int
}

// HaltInfo represents halt sentinel data
type HaltInfo struct {
	Reason      string
	TriggeredBy string
	TriggeredAt time.Time
}

// StatusInfo represents control plane status
type StatusInfo struct {
	ConfigExists   bool
	Config         *Config
	Halted         bool
	HaltInfo       *HaltInfo
	CommitsToday   int
	Violations     []string
	FixFeatRatio   string
	MetricsExist   bool
}

// CheckHalt reads ~/.orch/halt and returns (halted, reason)
func CheckHalt() (bool, string) {
	data, err := os.ReadFile(HaltPath)
	if err != nil {
		if os.IsNotExist(err) {
			return false, ""
		}
		return false, fmt.Sprintf("error reading halt file: %v", err)
	}

	// Parse halt file (simple key: value format)
	lines := strings.Split(string(data), "\n")
	reason := "unknown"
	for _, line := range lines {
		if strings.HasPrefix(line, "reason:") {
			reason = strings.TrimSpace(strings.TrimPrefix(line, "reason:"))
			break
		}
	}

	return true, reason
}

// ClearHalt removes ~/.orch/halt
func ClearHalt() error {
	err := os.Remove(HaltPath)
	if err != nil && !os.IsNotExist(err) {
		return fmt.Errorf("failed to clear halt: %w", err)
	}
	return nil
}

// LoadConfig reads ~/.orch/control-plane.conf
func LoadConfig() (*Config, error) {
	data, err := os.ReadFile(ConfigPath)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, fmt.Errorf("config not found: %s (run 'orch control init')", ConfigPath)
		}
		return nil, fmt.Errorf("failed to read config: %w", err)
	}

	cfg := &Config{
		CooldownMinutes: 30, // default
	}

	scanner := bufio.NewScanner(strings.NewReader(string(data)))
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())

		// Skip comments and empty lines
		if line == "" || strings.HasPrefix(line, "#") {
			continue
		}

		// Parse key=value
		parts := strings.SplitN(line, "=", 2)
		if len(parts) != 2 {
			continue
		}

		key := strings.TrimSpace(parts[0])
		value := strings.TrimSpace(parts[1])

		// Remove quotes if present
		value = strings.Trim(value, "\"")

		switch key {
		case "MAX_COMMITS_PER_DAY":
			if v, err := strconv.Atoi(value); err == nil {
				cfg.MaxCommitsPerDay = v
			}
		case "FIX_FEAT_RATIO_THRESHOLD":
			if v, err := strconv.Atoi(value); err == nil {
				cfg.FixFeatRatioThreshold = v
			}
		case "CHURN_RATIO_THRESHOLD":
			if v, err := strconv.Atoi(value); err == nil {
				cfg.ChurnRatioThreshold = v
			}
		case "PROTECTED_PATHS":
			// Split on spaces
			cfg.ProtectedPaths = strings.Fields(value)
		case "COOLDOWN_MINUTES":
			if v, err := strconv.Atoi(value); err == nil {
				cfg.CooldownMinutes = v
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("error parsing config: %w", err)
	}

	return cfg, nil
}

// ParseHaltInfo reads halt file and returns structured info
func ParseHaltInfo() (*HaltInfo, error) {
	data, err := os.ReadFile(HaltPath)
	if err != nil {
		return nil, err
	}

	info := &HaltInfo{}
	lines := strings.Split(string(data), "\n")
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, "reason:") {
			info.Reason = strings.TrimSpace(strings.TrimPrefix(line, "reason:"))
		} else if strings.HasPrefix(line, "triggered_by:") {
			info.TriggeredBy = strings.TrimSpace(strings.TrimPrefix(line, "triggered_by:"))
		} else if strings.HasPrefix(line, "triggered_at:") {
			timeStr := strings.TrimSpace(strings.TrimPrefix(line, "triggered_at:"))
			if t, err := time.Parse(time.RFC3339, timeStr); err == nil {
				info.TriggeredAt = t
			}
		}
	}

	return info, nil
}

// Status returns control plane state (config + halt + recent metrics)
func Status() (*StatusInfo, error) {
	status := &StatusInfo{}

	// Check config exists
	if _, err := os.Stat(ConfigPath); err == nil {
		status.ConfigExists = true
		if cfg, err := LoadConfig(); err == nil {
			status.Config = cfg
		}
	}

	// Check halt status
	if halted, _ := CheckHalt(); halted {
		status.Halted = true
		if info, err := ParseHaltInfo(); err == nil {
			status.HaltInfo = info
		}
	}

	// Read today's commit count from metrics
	commitsLogPath := filepath.Join(MetricsDir, "daily-commits.log")
	if data, err := os.ReadFile(commitsLogPath); err == nil {
		status.MetricsExist = true
		lines := strings.Split(string(data), "\n")
		today := time.Now().Format("2006-01-02")
		for i := len(lines) - 1; i >= 0; i-- {
			if strings.HasPrefix(lines[i], today) {
				parts := strings.Fields(lines[i])
				if len(parts) >= 2 {
					if count, err := strconv.Atoi(parts[1]); err == nil {
						status.CommitsToday = count
					}
					break
				}
			}
		}
	}

	// Read protected path violations from metrics
	violationsLogPath := filepath.Join(MetricsDir, "protected-violations.log")
	if data, err := os.ReadFile(violationsLogPath); err == nil {
		lines := strings.Split(string(data), "\n")
		today := time.Now().Format("2006-01-02")
		for _, line := range lines {
			if strings.Contains(line, today) {
				status.Violations = append(status.Violations, line)
			}
		}
	}

	// Read fix:feat ratio from metrics
	ratioLogPath := filepath.Join(MetricsDir, "fix-feat-ratio.log")
	if data, err := os.ReadFile(ratioLogPath); err == nil {
		lines := strings.Split(string(data), "\n")
		today := time.Now().Format("2006-01-02")
		for i := len(lines) - 1; i >= 0; i-- {
			if strings.HasPrefix(lines[i], today) {
				status.FixFeatRatio = strings.TrimPrefix(lines[i], today+" ")
				break
			}
		}
	}

	return status, nil
}

// InitConfig creates ~/.orch/control-plane.conf with defaults
func InitConfig() error {
	// Ensure directory exists
	if err := os.MkdirAll(ControlDir, 0755); err != nil {
		return fmt.Errorf("failed to create control dir: %w", err)
	}

	// Check if config already exists
	if _, err := os.Stat(ConfigPath); err == nil {
		return fmt.Errorf("config already exists: %s", ConfigPath)
	}

	defaultConfig := `# Control Plane Configuration
# Circuit breakers — daemon halts when threshold exceeded
MAX_COMMITS_PER_DAY=20
FIX_FEAT_RATIO_THRESHOLD=50    # percentage (50 = 0.5:1 fix:feat)
CHURN_RATIO_THRESHOLD=200      # percentage (200 = 2:1 created+deleted/net)

# Protected paths — violations logged, human notified
PROTECTED_PATHS="cmd/orch/ pkg/daemon/ pkg/spawn/ pkg/verify/ plugins/"

# Cooldown after circuit break
COOLDOWN_MINUTES=30
`

	if err := os.WriteFile(ConfigPath, []byte(defaultConfig), 0644); err != nil {
		return fmt.Errorf("failed to write config: %w", err)
	}

	return nil
}

package main

import (
	"fmt"
	"os"
	"strings"

	"github.com/dylan-conlin/orch-go/pkg/control"
	"github.com/spf13/cobra"
)

var controlCmd = &cobra.Command{
	Use:   "control",
	Short: "Manage control plane (circuit breakers, protected paths)",
	Long: `Control plane management commands.

The control plane is an immutable layer at ~/.orch/ that agents cannot modify.
It provides circuit breakers (commit limits, fix:feat ratios) and protected
path monitoring to prevent entropy spirals.

Commands:
  status  - Show control plane state and metrics
  resume  - Clear halt sentinel and resume daemon
  init    - Create default control-plane.conf`,
}

var controlStatusCmd = &cobra.Command{
	Use:   "status",
	Short: "Show control plane state and recent metrics",
	Long: `Show control plane configuration, halt status, and recent metrics.

Displays:
- Configuration location and thresholds
- Halt status (if circuit breaker fired)
- Today's commit count
- Protected path violations
- Fix:feat ratio (7-day rolling window)`,
	RunE: func(cmd *cobra.Command, args []string) error {
		status, err := control.Status()
		if err != nil {
			return fmt.Errorf("failed to get status: %w", err)
		}

		fmt.Println("Control Plane Status")
		fmt.Printf("  Config:      %s\n", control.ConfigPath)

		if !status.ConfigExists {
			fmt.Println("  State:       NOT INITIALIZED")
			fmt.Println()
			fmt.Println("Run 'orch control init' to create default configuration.")
			return nil
		}

		// Halt status
		if status.Halted {
			if status.HaltInfo != nil {
				fmt.Printf("  State:       HALTED (since %s)\n", status.HaltInfo.TriggeredAt.Format("2006-01-02 15:04 MST"))
				fmt.Printf("  Reason:      %s\n", status.HaltInfo.Reason)
			} else {
				fmt.Println("  State:       HALTED")
			}
		} else {
			fmt.Println("  State:       ACTIVE")
		}
		fmt.Println()

		// Thresholds
		cfg := status.Config
		if cfg != nil {
			fmt.Println("Thresholds:")

			// Commits per day
			if cfg.MaxCommitsPerDay > 0 {
				fmt.Printf("  Commits/day:     %d", cfg.MaxCommitsPerDay)
				if status.MetricsExist {
					fmt.Printf(" (current: %d)", status.CommitsToday)
					if status.CommitsToday >= cfg.MaxCommitsPerDay {
						fmt.Print(" ← EXCEEDED")
					}
				}
				fmt.Println()
			}

			// Fix:feat ratio
			if cfg.FixFeatRatioThreshold > 0 {
				fmt.Printf("  Fix:feat ratio:  %d%%", cfg.FixFeatRatioThreshold)
				if status.FixFeatRatio != "" {
					fmt.Printf(" (current: %s)", status.FixFeatRatio)
				}
				fmt.Println()
			}

			// Churn ratio
			if cfg.ChurnRatioThreshold > 0 {
				fmt.Printf("  Churn ratio:     %d%%\n", cfg.ChurnRatioThreshold)
			}

			// Protected paths
			if len(cfg.ProtectedPaths) > 0 {
				fmt.Printf("  Protected paths: %s\n", strings.Join(cfg.ProtectedPaths, " "))
			}
			fmt.Println()
		}

		// Today's metrics
		if status.MetricsExist {
			fmt.Println("Today's Metrics:")
			fmt.Printf("  Commits: %d\n", status.CommitsToday)

			if len(status.Violations) > 0 {
				fmt.Printf("  Protected path violations: %d\n", len(status.Violations))
				for _, v := range status.Violations {
					fmt.Printf("    %s\n", v)
				}
			} else {
				fmt.Println("  Protected path violations: 0")
			}
			fmt.Println()
		}

		// Action prompt
		if status.Halted {
			fmt.Println("Run 'orch control resume' to clear halt and continue.")
		}

		return nil
	},
}

var controlResumeCmd = &cobra.Command{
	Use:   "resume",
	Short: "Clear halt sentinel and resume daemon",
	Long: `Clear the halt sentinel file and resume daemon operations.

The daemon checks for the halt file at the top of each poll cycle.
Once cleared, the daemon will resume spawning agents on the next cycle
(within 60 seconds).

This command also displays current metrics as confirmation.`,
	RunE: func(cmd *cobra.Command, args []string) error {
		// Check if halted
		halted, reason := control.CheckHalt()
		if !halted {
			fmt.Println("Control plane is not halted.")
			return nil
		}

		fmt.Printf("Halted: %s\n", reason)
		fmt.Println()

		// Get current metrics before clearing
		status, _ := control.Status()
		if status != nil && status.MetricsExist {
			fmt.Println("Current Metrics:")
			fmt.Printf("  Commits today: %d\n", status.CommitsToday)
			if status.FixFeatRatio != "" {
				fmt.Printf("  Fix:feat ratio: %s\n", status.FixFeatRatio)
			}
			fmt.Println()
		}

		// Clear halt
		if err := control.ClearHalt(); err != nil {
			return fmt.Errorf("failed to clear halt: %w", err)
		}

		fmt.Println("✓ Halt cleared. Daemon will resume on next poll cycle (within 60s).")
		return nil
	},
}

var controlInitCmd = &cobra.Command{
	Use:   "init",
	Short: "Create default control-plane.conf",
	Long: `Create ~/.orch/control-plane.conf with default thresholds.

Default configuration:
- MAX_COMMITS_PER_DAY=20
- FIX_FEAT_RATIO_THRESHOLD=50 (0.5:1 fix:feat)
- CHURN_RATIO_THRESHOLD=200 (2:1 created+deleted/net)
- PROTECTED_PATHS="cmd/orch/ pkg/daemon/ pkg/spawn/ pkg/verify/ plugins/"
- COOLDOWN_MINUTES=30

After creating the config, you must install the post-commit hook manually:

Add this line to .git/hooks/post-commit:
  [ -x "$HOME/.orch/hooks/control-plane-post-commit.sh" ] && "$HOME/.orch/hooks/control-plane-post-commit.sh" || true

Then create the hook script:
  cp ~/.orch/templates/control-plane-post-commit.sh ~/.orch/hooks/
  chmod +x ~/.orch/hooks/control-plane-post-commit.sh`,
	RunE: func(cmd *cobra.Command, args []string) error {
		// Check if already exists
		if _, err := os.Stat(control.ConfigPath); err == nil {
			return fmt.Errorf("config already exists: %s", control.ConfigPath)
		}

		// Create config
		if err := control.InitConfig(); err != nil {
			return err
		}

		fmt.Printf("✓ Created: %s\n", control.ConfigPath)
		fmt.Println()
		fmt.Println("Default thresholds:")
		fmt.Println("  MAX_COMMITS_PER_DAY=20")
		fmt.Println("  FIX_FEAT_RATIO_THRESHOLD=50")
		fmt.Println("  PROTECTED_PATHS=\"cmd/orch/ pkg/daemon/ pkg/spawn/ pkg/verify/ plugins/\"")
		fmt.Println()
		fmt.Println("Next steps:")
		fmt.Println("1. Review and adjust thresholds in the config file")
		fmt.Println("2. Install the post-commit hook (see 'orch control init --help')")

		return nil
	},
}

func init() {
	controlCmd.AddCommand(controlStatusCmd)
	controlCmd.AddCommand(controlResumeCmd)
	controlCmd.AddCommand(controlInitCmd)
}

